#include <stdio.h>
#include <math.h>
int main() {
    int n;
    scanf("%d", &n);
    int total = 0;
    for (int i = 0; i < n; i++) {
        int ti;
        scanf("%d", &ti);
        total += (ti + 1) / 2;
    }
    printf("%d\n", total);
    return 0;
}

